  "code": "def parse_csv(csv_string):\n    # Split the CSV string into rows\n    rows = csv_string.strip().split('\\n')\n    # Extract headers from the first row\n    headers = rows[0].split(', ')\n    # Initialize a list to store dictionaries\n    data = []\n    # Iterate over the remaining rows starting from the second one\n    for row in rows[1:]:\n        # Split the row into values\n        values = row.split(', ')\n        # Create a dictionary with headers as keys and values as items\n        item = {headers[i]: values[i] for i in range(len(headers))}\n        # Append the dictionary to the data list\n        data.append(item)\n    return data",
