{
  "task_summary": "Reads a text file path in a Node.js environment and returns line count, word count, and character count.",
  "approach": "Use Node.js's built-in `fs` module to read the file content, then split it into lines, words, and characters to calculate their respective counts.",
  "code": "```typescript
import * as fs from 'fs';

function analyzeFile(filePath: string): Promise<{ lineCount: number, wordCount: number, charCount: number }> {
  return new Promise((resolve, reject) => {
    fs.readFile(filePath, 'utf8', (err, data) => {
      if (err) {
        reject(err);
        return;
      }

      const lines = data.split('\n').filter(line => line.trim() !== '');
      const words = data.match(/\b\w+\b/g) || [];
      const charCount = data.length;

      resolve({ lineCount: lines.length, wordCount: words.length, charCount });
    });
  });
}
