    const sampleFileResult = await readTextFile('./sample.txt'); // Path to a short sample text file
    console.log('Sample file result:', sampleFileResult); // Expected: { lines: 3, words: 6, chars: 21 }
  } catch (error) {
    console.error('Error reading files:', error);
  }
})();
