{
  "task_summary": "Topologically sort tasks based on their dependencies",
  "approach": "Use Kahn's algorithm to detect cycles and topologically sort the tasks",
  "code": "def topological_sort(dependencies):
    # Initialize in-degree dictionary
    indegree = {task: 0 for task in dependencies}
    # Calculate in-degrees of all tasks
    for task, deps in dependencies.items():
        for dep in deps:
            indegree[dep] += 1

    # Queue to store nodes with zero in-degree
    queue = [task for task in indegree if indegree[task] == 0]
    sorted_tasks = []

    while queue:
        current_task = queue.pop(0)
        sorted_tasks.append(current_task)

        # Decrease the in-degrees of all adjacent nodes
        for dep in dependencies[current_task]:
            indegree[dep] -= 1

            # If an adjacent node has zero in-degree, add it to the queue
            if indegree[dep] == 0:
                queue.append(dep)

    # Check for cycles
    if len(sorted_tasks) != len(dependencies):
        return 'Cycle detected'

    return sorted_tasks",
  "complexity": {
    "time": "O(V + E)",
    "space": "O(V)"
  },
